parameters.query:
CREATE TABLE IF NOT EXISTS lorena_debounce (
  subscriber_id TEXT PRIMARY KEY,
  messages      TEXT NOT NULL DEFAULT '',
  last_ts       BIGINT NOT NULL
);

INSERT INTO lorena_debounce (subscriber_id, messages, last_ts)
VALUES (
  '{{ $('Webhook').item.json.body.data.id }}',
  '{{ $('Webhook').item.json.body.msg.replace(/'/g, "''") }}',
  {{ Date.now() }}
)
ON CONFLICT (subscriber_id) DO UPDATE SET
  messages = lorena_debounce.messages || E'\n' || EXCLUDED.messages,
  last_ts  = EXCLUDED.last_ts
RETURNING last_ts;

parameters.jsCode:
// Debounce: se outro webhook chegou DEPOIS de mim, o last_ts no banco
// será diferente do meu. Nesse caso, descarto esta execução —
// a execução mais recente vai processar todas as mensagens acumuladas.

// Recuperar MEU timestamp (do INSERT/UPDATE que eu mesmo fiz)
const gravar = $('Gravar msg no Postgres').item.json;
const myTs = Number(
  Array.isArray(gravar) ? gravar[0]?.last_ts :
  gravar?.[0]?.last_ts ?? gravar?.last_ts ?? 0
);

// Recuperar timestamp ATUAL do banco (depois dos 4s de espera)
const checar = $input.item.json;
const dbTs = Number(
  Array.isArray(checar) ? checar[0]?.last_ts :
  checar?.[0]?.last_ts ?? checar?.last_ts ?? 0
);

// Se algum dos dois é inválido, melhor descartar para evitar duplicação
if (!myTs || !dbTs) {
  console.log('[debounce] timestamps inválidos, descartando', { myTs, dbTs });
  return [];
}

// Se uma mensagem mais nova chegou, o dbTs será maior — descarto esta
if (dbTs !== myTs) {
  console.log('[debounce] não sou o último, descartando', { myTs, dbTs });
  return [];
}

console.log('[debounce] sou o último, prosseguindo', { myTs });
return [{ json: $input.item.json }];

