const webhookData  = $('Webhook').item.json;
const subscriberId = webhookData.body.data.id;

const rawMsgs = $('Deletar e recuperar msgs').item.json[0]?.messages
             ?? $('Deletar e recuperar msgs').item.json?.messages
             ?? webhookData.body.msg ?? '';
const msg = rawMsgs.trim();

let userInfo = {};
try {
  const raw = $('Buscar dados do usuário').item.json;
  if (raw && raw.data) userInfo = raw.data;
} catch(e) {}

const firstName = userInfo.first_name || '';
const lastName  = userInfo.last_name  || '';
const fullName  = [firstName, lastName].filter(Boolean).join(' ') || 'Cliente';
const city      = userInfo.city   || '';
const gender    = userInfo.gender || '';
const tags      = (userInfo.tags || []).map(t => t.name).join(', ') || 'nenhuma';

const contextBlock = [
  `Nome do cliente: ${fullName}`,
  city   ? `Cidade: ${city}`   : null,
  gender ? `Gênero: ${gender}` : null,
  `Tags ManyChat: ${tags}`,
].filter(Boolean).join('\n');

return [{
  json: { subscriberId, msg, fullName, userContext: contextBlock }
}];

// Detecta se o agente respondeu corretamente e se está pronto para handoff
const raw = $input.item.json;
const agentOutput = (raw?.output || '').toString().trim();
const agentError = !agentOutput;
const readyForHuman = !agentError && agentOutput.includes('[PRONTO_PARA_CONSULTOR]');
const cleanOutput = agentOutput.replace('[PRONTO_PARA_CONSULTOR]', '').trim();

const ctx = $('Montar contexto').item.json;

return [{
  json: {
    output: cleanOutput,
    readyForHuman,
    agentError,
    subscriberId: ctx.subscriberId,
    userContext: ctx.userContext,
    msg: ctx.msg,
    fullName: ctx.fullName
  }
}];

const ctx = $('Montar contexto').item.json;
return [{ json: {
  subscriberId: ctx.subscriberId,
  output: 'Olá! Estamos verificando sua solicitação. Em instantes, uma de nossas consultoras do Instituto Lorena Visentainer entrará em contato. 💆'
}}];

// ─── GERAR RESUMO PARA O CONSULTOR ────────────────────────────────────────
// Monta um briefing estruturado com tudo que foi coletado na conversa.

const output      = $json.output      || '';
const msg         = $json.msg         || '';
const fullName    = $json.fullName    || 'Não identificado';
const userContext = $json.userContext || '';
const subscriberId = $json.subscriberId;

const now = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

const summary = [
  '💆 *Instituto Lorena Visentainer — Paciente qualificado para atendimento*',
  '',
  `📋 *Cliente:* ${fullName}`,
  `🕐 *Horário:* ${now}`,
  `🆔 *Subscriber ID:* ${subscriberId}`,
  '',
  `📊 *Dados do perfil:*`,
  userContext,
  '',
  `💬 *Última mensagem do cliente:*`,
  `"${msg}"`,
  '',
  `🤖 *Última resposta do assistente:*`,
  output,
  '',
  '✅ *Ação:* O paciente demonstrou interesse concreto no transplante capilar. Por favor, assuma o atendimento.'
].join('\n');

return [
  {
    json: {
      ...$json,
      consultorSummary: summary
    }
  }
];
